using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a resource from the external API by its unique identifier.")]
    public async Task<string> FetchResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        logger.LogInformation("Successfully fetched resource {Id}", id);
        return json;
    }

    [McpServerTool, Description("Search the external API with a query string and return matching results.")]
    public async Task<string> SearchApi(
        [Description("The search query to send to the API")] string query,
        [Description("Maximum number of results to return (1-100)")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching API with query '{Query}', maxResults={Max}", query, maxResults);
        var response = await httpClient.GetAsync(
            $"/api/search?q={Uri.EscapeDataString(query)}&limit={maxResults}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The content to summarize")] string content) =>
        new(ChatRole.User, $"Please summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content with a specific focus or angle.")]
    public static ChatMessage SummarizeWithFocus(
        [Description("The content to summarize")] string content,
        [Description("The specific aspect or angle to focus on")] string focus) =>
        new(ChatRole.User,
            $"Please summarize the following content, focusing specifically on {focus}:\n\n{content}");
}

